function SimulatorCard({
  parentOrderId,
  history,
  onSubmitted,
}: {
  parentOrderId: string;
  history: SimRecord[];
  onSubmitted: (simOrderId: string) => void;
}) {
  const [draft, setDraft] = useState("");
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const getClientToken = () => {
    try {
      const KEY = "ai-unni-client-token";
      let t = localStorage.getItem(KEY);
      if (!t) {
        t = crypto.randomUUID();
        localStorage.setItem(KEY, t);
      }
      return t;
    } catch {
      return "anon-" + Date.now();
    }
  };

  const handleSubmit = async () => {
    if (!draft.trim() || submitting) return;
    if (draft.length > 1000) {
      setError("답안은 1000자 이하로 써줘");
      return;
    }
    setSubmitting(true);
    setError(null);
    try {
      const res = await fetch("/api/simulation/request", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          parent_order_id: parentOrderId,
          draft_reply: draft.trim(),
          clientToken: getClientToken(),
        }),
      });
      const json = await res.json();
      if (!res.ok || !json.sim_order_id) {
        throw new Error(json?.error || "시뮬 주문 생성 실패");
      }
      onSubmitted(json.sim_order_id);
      // 결제 페이지로 이동 (체크아웃은 type=sim 으로 분기)
      window.location.href = `/checkout?orderId=${encodeURIComponent(json.sim_order_id)}&type=sim`;
    } catch (e: any) {
      setError(e?.message || "오류가 났어. 다시 해볼래?");
      setSubmitting(false);
    }
  };

  const remaining = 1000 - draft.length;

  return (
    <div className="mt-6 mb-2 animate-fadeUp">
      {/* 섹션 헤더 */}
      <div className="text-center mb-3">
        <div className="text-[18px] font-extrabold text-[#2D2B3D] mb-1">
          💬 이 답장, 보내도 될까?
        </div>
        <div className="text-[12px] text-[#6E6A80] leading-[1.55] px-3">
          네가 보낼 답장을 써봐. 걔 시점에서 어떻게 받아들일지<br />
          반응·감정 변화·리스크까지 미리 돌려봐줄게.
        </div>
      </div>

      {/* 입력 카드 */}
      <div
        className="rounded-[18px] p-3.5 bg-white mb-2.5"
        style={{
          border: "1px solid #FFD6E0",
          boxShadow: "0 2px 14px rgba(255,107,138,0.08)",
        }}>
        <textarea
          value={draft}
          onChange={(e) => setDraft(e.target.value)}
          maxLength={1000}
          placeholder="예: 요즘 너무 바쁜 거 같던데, 이번 주말엔 시간 어때? 잠깐이라도 얼굴 보고 싶어서."
          rows={5}
          className="w-full resize-none text-[13.5px] leading-[1.7] text-[#2D2B3D] outline-none rounded-[12px] p-3"
          style={{
            background: "#FFF8FA",
            border: "1px solid #FFE8EC",
            fontFamily: "inherit",
          }}
        />
        <div className="flex justify-between items-center mt-1.5 text-[11px]">
          <span className="text-[#A09CB0]">📱 카톡·DM에 보낼 답장 그대로</span>
          <span className={remaining < 100 ? "text-[#E8456A] font-bold" : "text-[#A09CB0]"}>
            {draft.length}/1000
          </span>
        </div>
      </div>

      {error && (
        <div className="bg-white rounded-[14px] p-3 mb-2.5 border border-[#FFB3B3] text-[12px] text-[#D14343]">
          {error}
        </div>
      )}

      {/* CTA */}
      <button
        onClick={handleSubmit}
        disabled={!draft.trim() || submitting}
        className="w-full py-3.5 rounded-[16px] text-white text-[14px] font-bold transition-all"
        style={{
          background:
            draft.trim() && !submitting
              ? "linear-gradient(135deg, #FF6B8A, #E8456A)"
              : "#D0CDE0",
          boxShadow:
            draft.trim() && !submitting ? "0 4px 18px rgba(255,107,138,0.25)" : "none",
          border: "none",
          cursor: draft.trim() && !submitting ? "pointer" : "not-allowed",
        }}>
        {submitting
          ? "결제창으로 이동 중..."
          : `🔮 시뮬 받기 · ₩${SIM_AMOUNT.toLocaleString()}`}
      </button>

      <p className="text-center mt-2 text-[10.5px] text-[#A09CB0] leading-[1.5]">
        결제 1회당 시뮬 1회 · 같은 분석 맥락으로 답안 여러 번 돌려볼 수 있어
      </p>

      {/* 시뮬 히스토리 */}
      {history.length > 0 && (
        <div className="mt-5">
          <div className="text-[12px] font-bold text-[#2D2B3D] mb-2 px-1">
            🕐 지난 시뮬 결과 ({history.length})
          </div>
          {history.map((rec) => (
            <SimResultCard key={rec.sim_order_id} rec={rec} />
          ))}
        </div>
      )}
    </div>
  );
}

